@inject IJSRuntime JS
@implements IAsyncDisposable

<div @ref="_dropZoneRef" class="file-drop-zone @(_isDragOver ? "drag-over" : "")">
    <p>Drag &amp; drop files here</p>
</div>

@if (_files.Count > 0)
{
    <ul class="file-drop-zone-list">
        @foreach (var file in _files)
        {
            <li class="@(file.HasError ? "file-error" : "")">
                @if (file.HasError)
                {
                    <span class="file-error-message">@file.ErrorMessage</span>
                    <span class="file-name">@file.Info.Name</span>
                }
                else
                {
                    <span class="file-name">@file.Info.Name</span>
                    <span class="file-size">@FormatSize(file.Info.Size)</span>
                    <span class="file-type">@file.Info.Type</span>
                }
                <button class="btn-remove" @onclick="() => RemoveFile(file)">Remove</button>
            </li>
        }
    </ul>
}

@code {
    private const long MaxFileSizeBytes = 10 * 1024 * 1024; // 10 MB

    private ElementReference _dropZoneRef;
    private IJSObjectReference? _module;
    private DotNetObjectReference<FileDropZone>? _dotNetRef;
    private bool _isDragOver;
    private readonly List<FileEntry> _files = new();

    [Parameter]
    public EventCallback<List<FileInfo>> OnFilesChanged { get; set; }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _module = await JS.InvokeAsync<IJSObjectReference>("import",
                "./_content/sv-4a076c4aa55648bfac2fb19cc8428666/Components/FileDropZone.razor.js");
            _dotNetRef = DotNetObjectReference.Create(this);
            await _module.InvokeVoidAsync("initDropZone", _dropZoneRef, _dotNetRef);
        }
    }

    [JSInvokable]
    public void OnDragEnter() 
    {
        _isDragOver = true;
        StateHasChanged();
    }

    [JSInvokable]
    public void OnDragLeave()
    {
        _isDragOver = false;
        StateHasChanged();
    }

    [JSInvokable]
    public async Task OnFilesDropped(List<FileInfo> droppedFiles)
    {
        _isDragOver = false;

        foreach (var file in droppedFiles)
        {
            if (file.Size > MaxFileSizeBytes)
            {
                _files.Add(new FileEntry(file, true, $"File exceeds 10 MB limit ({FormatSize(file.Size)})"));
            }
            else
            {
                _files.Add(new FileEntry(file, false, null));
            }
        }

        await NotifyParent();
        StateHasChanged();
    }

    private async Task RemoveFile(FileEntry entry)
    {
        _files.Remove(entry);
        await NotifyParent();
    }

    private async Task NotifyParent()
    {
        var validFiles = _files
            .Where(f => !f.HasError)
            .Select(f => f.Info)
            .ToList();
        await OnFilesChanged.InvokeAsync(validFiles);
    }

    private static string FormatSize(long bytes)
    {
        return bytes switch
        {
            < 1024 => $"{bytes} B",
            < 1024 * 1024 => $"{bytes / 1024.0:F1} KB",
            _ => $"{bytes / (1024.0 * 1024.0):F1} MB"
        };
    }

    public async ValueTask DisposeAsync()
    {
        if (_module is not null)
        {
            await _module.InvokeVoidAsync("dispose", _dropZoneRef);
            await _module.DisposeAsync();
        }
        _dotNetRef?.Dispose();
    }

    private record FileEntry(FileInfo Info, bool HasError, string? ErrorMessage);
}

const dropZoneMap = new Map();

export function initDropZone(element, dotNetRef) {
    let dragCounter = 0;

    function onDragOver(e) {
        e.preventDefault();
        e.stopPropagation();
    }

    function onDragEnter(e) {
        e.preventDefault();
        e.stopPropagation();
        dragCounter++;
        if (dragCounter === 1) {
            dotNetRef.invokeMethodAsync('OnDragEnter');
        }
    }

    function onDragLeave(e) {
        e.preventDefault();
        e.stopPropagation();
        dragCounter--;
        if (dragCounter === 0) {
            dotNetRef.invokeMethodAsync('OnDragLeave');
        }
    }

    function onDrop(e) {
        e.preventDefault();
        e.stopPropagation();
        dragCounter = 0;

        const files = [];
        if (e.dataTransfer && e.dataTransfer.files) {
            for (const file of e.dataTransfer.files) {
                files.push({ name: file.name, size: file.size, type: file.type || 'unknown' });
            }
        }

        dotNetRef.invokeMethodAsync('OnFilesDropped', files);
    }

    element.addEventListener('dragover', onDragOver);
    element.addEventListener('dragenter', onDragEnter);
    element.addEventListener('dragleave', onDragLeave);
    element.addEventListener('drop', onDrop);

    dropZoneMap.set(element, { onDragOver, onDragEnter, onDragLeave, onDrop });
}

export function dispose(element) {
    const handlers = dropZoneMap.get(element);
    if (handlers) {
        element.removeEventListener('dragover', handlers.onDragOver);
        element.removeEventListener('dragenter', handlers.onDragEnter);
        element.removeEventListener('dragleave', handlers.onDragLeave);
        element.removeEventListener('drop', handlers.onDrop);
        dropZoneMap.delete(element);
    }
}

.file-drop-zone {
    border: 2px dashed #6c757d;
    border-radius: 8px;
    padding: 2rem;
    text-align: center;
    color: #6c757d;
    transition: border-color 0.2s, background-color 0.2s;
    cursor: default;
}

.file-drop-zone.drag-over {
    border-color: #0d6efd;
    background-color: rgba(13, 110, 253, 0.05);
    color: #0d6efd;
}

.file-drop-zone-list {
    list-style: none;
    padding: 0;
    margin-top: 1rem;
}

.file-drop-zone-list li {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    padding: 0.5rem 0.75rem;
    border: 1px solid #dee2e6;
    border-radius: 4px;
    margin-bottom: 0.5rem;
}

.file-drop-zone-list li.file-error {
    border-color: #dc3545;
    background-color: rgba(220, 53, 69, 0.05);
}

.file-error-message {
    color: #dc3545;
    font-weight: 500;
}

.file-name {
    font-weight: 500;
}

.file-size,
.file-type {
    color: #6c757d;
    font-size: 0.875rem;
}

.btn-remove {
    margin-left: auto;
    border: none;
    background: #dc3545;
    color: white;
    border-radius: 4px;
    padding: 0.25rem 0.5rem;
    font-size: 0.8rem;
    cursor: pointer;
}

.btn-remove:hover {
    background: #bb2d3b;
}

