@inject IJSRuntime JS
@implements IAsyncDisposable

<div @ref="_dropZoneRef" class="file-drop-zone @(_isDragOver ? "drag-over" : "")">
    <p>Drag &amp; drop files here</p>
</div>

@if (_files.Count > 0)
{
    <ul class="file-drop-zone-list">
        @foreach (var file in _files)
        {
            <li class="@(file.HasError ? "file-error" : "")">
                @if (file.HasError)
                {
                    <span class="file-error-message">@file.ErrorMessage</span>
                    <span class="file-name">@file.Info.Name</span>
                }
                else
                {
                    <span class="file-name">@file.Info.Name</span>
                    <span class="file-size">@FormatSize(file.Info.Size)</span>
                    <span class="file-type">@file.Info.Type</span>
                }
                <button class="btn-remove" @onclick="() => RemoveFile(file)">Remove</button>
            </li>
        }
    </ul>
}

@code {
    private const long MaxFileSizeBytes = 10 * 1024 * 1024; // 10 MB

    private ElementReference _dropZoneRef;
    private IJSObjectReference? _module;
    private DotNetObjectReference<FileDropZone>? _dotNetRef;
    private bool _isDragOver;
    private readonly List<FileEntry> _files = new();

    [Parameter]
    public EventCallback<List<FileInfo>> OnFilesChanged { get; set; }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _module = await JS.InvokeAsync<IJSObjectReference>("import",
                "./_content/sv-4a076c4aa55648bfac2fb19cc8428666/Components/FileDropZone.razor.js");
            _dotNetRef = DotNetObjectReference.Create(this);
            await _module.InvokeVoidAsync("initDropZone", _dropZoneRef, _dotNetRef);
        }
    }

    [JSInvokable]
    public void OnDragEnter() 
    {
        _isDragOver = true;
        StateHasChanged();
    }

    [JSInvokable]
    public void OnDragLeave()
    {
        _isDragOver = false;
        StateHasChanged();
    }

    [JSInvokable]
    public async Task OnFilesDropped(List<FileInfo> droppedFiles)
    {
        _isDragOver = false;

        foreach (var file in droppedFiles)
        {
            if (file.Size > MaxFileSizeBytes)
            {
                _files.Add(new FileEntry(file, true, $"File exceeds 10 MB limit ({FormatSize(file.Size)})"));
            }
            else
            {
                _files.Add(new FileEntry(file, false, null));
            }
        }

        await NotifyParent();
        StateHasChanged();
    }

    private async Task RemoveFile(FileEntry entry)
    {
        _files.Remove(entry);
        await NotifyParent();
    }

    private async Task NotifyParent()
    {
        var validFiles = _files
            .Where(f => !f.HasError)
            .Select(f => f.Info)
            .ToList();
        await OnFilesChanged.InvokeAsync(validFiles);
    }

    private static string FormatSize(long bytes)
    {
        return bytes switch
        {
            < 1024 => $"{bytes} B",
            < 1024 * 1024 => $"{bytes / 1024.0:F1} KB",
            _ => $"{bytes / (1024.0 * 1024.0):F1} MB"
        };
    }

    public async ValueTask DisposeAsync()
    {
        if (_module is not null)
        {
            await _module.InvokeVoidAsync("dispose", _dropZoneRef);
            await _module.DisposeAsync();
        }
        _dotNetRef?.Dispose();
    }

    private record FileEntry(FileInfo Info, bool HasError, string? ErrorMessage);
}

